/// Convert a `kreuzcrawl::CrawlError` error to a Magnus runtime error.
#[allow(dead_code)]
fn crawl_error_to_magnus_err(e: kreuzcrawl::CrawlError) -> magnus::Error {
    let msg = e.to_string();
    magnus::Error::new(magnus::exception::runtime_error(), msg)
}

